import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import { orderApi } from '../api/client';
import { useTracking } from '../hooks/useTracking';

// Leaflet default icon fix
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl:       'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl:     'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

const STATUS_LABELS = {
  PENDING:    { label: 'Kutilmoqda',        color: '#378ADD' },
  SEARCHING:  { label: 'Kuryer qidirilmoqda', color: '#EF9F27' },
  ASSIGNED:   { label: 'Kuryer tayinlandi',  color: '#0D7A6A' },
  PICKED_UP:  { label: 'Olib ketildi',      color: '#0D7A6A' },
  ON_THE_WAY: { label: 'Yo\'lda',           color: '#0D7A6A' },
  DELIVERED:  { label: '✓ Yetkazildi',      color: '#27500A' },
  CANCELLED:  { label: 'Bekor qilindi',     color: '#A32D2D' },
  FAILED:     { label: 'Muvaffaqiyatsiz',   color: '#A32D2D' },
};

const STEPS = ['SEARCHING','ASSIGNED','PICKED_UP','ON_THE_WAY','DELIVERED'];

export default function TrackingPage() {
  const { id }              = useParams();
  const [order, setOrder]   = useState(null);
  const [loading, setLoading] = useState(true);
  const { location, connected } = useTracking(id);

  useEffect(() => {
    orderApi.getById(id)
      .then(({ data }) => setOrder(data.data))
      .catch((err) => {
        // 401 bo'lsa interceptor /login ga o'tkazadi — biz hech narsa qilmaymiz
        if (err?.response?.status !== 401) {
          setLoading(false);
        }
      })
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return <div style={s.center}>Yuklanmoqda...</div>;
  if (!order)  return <div style={s.center}>Buyurtma topilmadi</div>;

  const status = STATUS_LABELS[order.status] || STATUS_LABELS.PENDING;
  const stepIdx = STEPS.indexOf(order.status);

  const courierPos = location?.available
    ? [location.lat, location.lng]
    : null;

  const pickupPos   = [order.pickupLat,   order.pickupLng];
  const deliveryPos = [order.deliveryLat, order.deliveryLng];
  const mapCenter   = courierPos || pickupPos;

  return (
    <div style={s.page}>
      <div style={s.header}>
        <div>
          <div style={s.orderId}>#{order.id?.slice(0,8).toUpperCase()}</div>
          <span style={{ ...s.statusBadge, background: status.color + '20', color: status.color }}>
            {status.label}
          </span>
        </div>
        <div style={s.fee}>{order.totalFee?.toLocaleString()} so'm</div>
      </div>

      {/* Progress steps */}
      <div style={s.steps}>
        {STEPS.map((step, i) => (
          <div key={step} style={s.stepItem}>
            <div style={{
              ...s.stepDot,
              background: i < stepIdx ? '#0D7A6A' : i === stepIdx ? '#EF9F27' : '#E1F5EE',
              color:       i <= stepIdx ? '#fff' : '#6b8080',
            }}>
              {i < stepIdx ? '✓' : i + 1}
            </div>
            {i < STEPS.length - 1 && (
              <div style={{ ...s.stepLine, background: i < stepIdx ? '#0D7A6A' : '#E1F5EE' }} />
            )}
          </div>
        ))}
      </div>

      {/* Leaflet Map */}
      <div style={s.mapWrap}>
        <MapContainer center={mapCenter} zoom={13} style={{ height: '100%', width: '100%' }}>
          <TileLayer
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
          />
          <Marker position={pickupPos}>
            <Popup>📦 Pickup: {order.pickupAddress}</Popup>
          </Marker>
          <Marker position={deliveryPos}>
            <Popup>🏠 Yetkazish: {order.deliveryAddress}</Popup>
          </Marker>
          {courierPos && (
            <Marker position={courierPos}>
              <Popup>🚴 Kuryer {connected ? '(real-time)' : ''}</Popup>
            </Marker>
          )}
        </MapContainer>
      </div>

      {/* Details */}
      <div style={s.card}>
        <Row label="Pickup"   value={order.pickupAddress} />
        <Row label="Yetkazish" value={order.deliveryAddress} />
        <Row label="Masofa"   value={order.distanceKm ? `${order.distanceKm} km` : '—'} />
        <Row label="WebSocket" value={connected ? '🟢 Ulangan' : '⭕ Ulanmagan'} />
      </div>
    </div>
  );
}

function Row({ label, value }) {
  return (
    <div style={{ display:'flex', justifyContent:'space-between', padding:'8px 0',
                  borderBottom:'1px solid rgba(0,0,0,0.05)', fontSize:13 }}>
      <span style={{ color:'#6b8080' }}>{label}</span>
      <span style={{ fontWeight:500 }}>{value}</span>
    </div>
  );
}

const s = {
  page:       { maxWidth: 680, margin: '0 auto', padding: '16px' },
  center:     { textAlign:'center', padding: 40, color:'#6b8080' },
  header:     { display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:16 },
  orderId:    { fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:18, color:'#1a2e2a' },
  statusBadge:{ display:'inline-block', padding:'4px 12px', borderRadius:20, fontSize:12,
                fontWeight:700, marginTop:6 },
  fee:        { fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:20, color:'#0D7A6A' },
  steps:      { display:'flex', alignItems:'center', marginBottom:16 },
  stepItem:   { display:'flex', alignItems:'center', flex:1 },
  stepDot:    { width:28, height:28, borderRadius:'50%', display:'flex', alignItems:'center',
                justifyContent:'center', fontSize:12, fontWeight:700, flexShrink:0 },
  stepLine:   { flex:1, height:3, borderRadius:4 },
  mapWrap:    { height:300, borderRadius:14, overflow:'hidden', marginBottom:16,
                border:'1px solid rgba(13,122,106,0.15)' },
  card:       { background:'#fff', border:'1px solid rgba(13,122,106,0.15)', borderRadius:14, padding:16 },
};
